using System.Collections.Generic;
using Xunit;

namespace ConfigBoundNET.Tests;

/// <summary>
/// End-to-end tests for the AOT-safe binder generated by
/// <see cref="ConfigBoundGenerator"/>. Each test compiles a synthetic
/// <c>[ConfigSection]</c> type, runs the generator, builds an in-memory
/// configuration, and asserts on the resulting <c>IOptions&lt;T&gt;.Value</c>.
/// </summary>
/// <remarks>
/// Together these prove the entire reflection-free pipeline works:
/// generator → ConfigBoundOptionsFactory replacement →
/// generated constructor → IConfiguration read.
/// They are intentionally one test per <see cref="BindingStrategy"/> branch
/// so a regression in any single strategy fails a single, named test.
/// </remarks>
public sealed class BindingTests
{
    [Fact]
    public void String_property_is_bound_from_section()
    {
        const string Source = """
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("Test")]
            public partial record TestConfig
            {
                public string Conn { get; init; } = default!;
            }
            """;

        var bound = GeneratorHarness.CompileAndBind(
            Source,
            "TestConfig",
            new Dictionary<string, string?> { ["Test:Conn"] = "hello world" });

        Assert.Equal("hello world", GetProp(bound, "Conn"));
    }

    [Fact]
    public void Missing_string_falls_back_to_field_initializer_default()
    {
        const string Source = """
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("Test")]
            public partial record TestConfig
            {
                public string Region { get; init; } = "fallback";
            }
            """;

        // Provide an unrelated key so the section exists but Region is absent.
        var bound = GeneratorHarness.CompileAndBind(
            Source,
            "TestConfig",
            new Dictionary<string, string?> { ["Test:OtherKey"] = "noise" });

        Assert.Equal("fallback", GetProp(bound, "Region"));
    }

