    [Fact]
    public void Sensitive_config_enumerates_as_KVPs_with_redaction()
    {
        // foreach over the interface cast — the path Serilog's
        // default destructurer actually takes when it sees
        // IEnumerable<KeyValuePair<string, object?>>.
        const string Source = """
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("Db")]
            public partial record DbConfig
            {
                [Sensitive]
                public string Conn { get; init; } = default!;
                public int Port { get; init; }
            }
            """;

        var bound = GeneratorHarness.CompileAndBind(
            Source,
            "DbConfig",
            new System.Collections.Generic.Dictionary<string, string?>
            {
                ["Db:Conn"] = "Server=secret-host",
                ["Db:Port"] = "5432",
            });

        var dict = (System.Collections.Generic.IReadOnlyDictionary<string, object?>)bound;
        var pairs = new System.Collections.Generic.List<System.Collections.Generic.KeyValuePair<string, object?>>();
        foreach (var kvp in dict)
        {
            pairs.Add(kvp);
        }

        Assert.Equal(2, pairs.Count);
        Assert.Equal("Conn", pairs[0].Key);
        Assert.Equal("***", pairs[0].Value);
        Assert.Equal("Port", pairs[1].Key);
        Assert.Equal(5432, pairs[1].Value);
    }

    [Fact]
    public void Sensitive_config_json_serialization_redacts_through_dictionary_path()
    {
        // The end-to-end "transparent across frameworks" proof:
        // JsonSerializer.Serialize(config) with NO custom converter, NO
        // source-gen context, and NO ToString involvement. STJ picks its
        // ReadOnlyDictionaryConverter for our type and writes each property
        // as a JSON key with the (possibly redacted) value.
        //
        // This is what MEL's JsonConsoleFormatter and most OpenTelemetry
        // JSON log exporters do under the hood when they serialize a
        // structured-log argument.
        const string Source = """
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("Db")]
            public partial record DbConfig
            {
                [Sensitive]
                public string Conn { get; init; } = default!;
                public int Port { get; init; }
            }
            """;

        var bound = GeneratorHarness.CompileAndBind(
            Source,
            "DbConfig",
            new System.Collections.Generic.Dictionary<string, string?>
            {
                ["Db:Conn"] = "Server=secret-host;Password=hunter2",
                ["Db:Port"] = "5432",
            });

        // Cast to object so STJ picks the runtime-type converter — matches
        // how MEL and OTel serialize log-scope arguments (they have a
        // System.Object-typed slot, not a strongly-typed one).
        var json = System.Text.Json.JsonSerializer.Serialize((object)bound);

        Assert.Contains("\"Conn\":\"***\"", json);
        Assert.Contains("\"Port\":5432", json);
        Assert.DoesNotContain("hunter2", json);
        Assert.DoesNotContain("secret-host", json);
    }

    // ── Aggregate registration tests ─────────────────────────────────────

    [Fact]
    public void AddConfigBoundSections_registers_every_present_section()
    {
        // Two [ConfigSection] types, both sections present in config. The
        // aggregate extension must register both and bind both correctly.
        const string Source = """
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("Db")]
            public partial record DbConfig
            {
                public string Conn { get; init; } = default!;
            }

            [ConfigSection("Api")]
            public partial record ApiConfig
            {
                public string BaseUrl { get; init; } = default!;
            }
            """;

        var dbBound = GeneratorHarness.CompileAndBindViaAggregate(
            Source,
            "DbConfig",
            new System.Collections.Generic.Dictionary<string, string?>
            {
                ["Db:Conn"] = "Server=localhost",
                ["Api:BaseUrl"] = "https://api.example/",
            });

        Assert.Equal("Server=localhost", GetProp(dbBound, "Conn"));

        // Second resolve against the aggregate path too, to prove both types
        // were actually registered.
        var apiBound = GeneratorHarness.CompileAndBindViaAggregate(
            Source,
            "ApiConfig",
            new System.Collections.Generic.Dictionary<string, string?>
            {
                ["Db:Conn"] = "Server=localhost",
                ["Api:BaseUrl"] = "https://api.example/",
            });

        Assert.Equal("https://api.example/", GetProp(apiBound, "BaseUrl"));
    }

    [Fact]
    public void AddConfigBoundSections_skips_nested_referenced_type_whose_section_is_absent()
    {
        // The gate now fires only for types the aggregate classifies as
        // nested — either via a nested-property reference from another
        // [ConfigSection] (the inference path exercised here) or via an
        // explicit IsNestedOnly=true flag on the attribute. This fixture
        // embeds List<TenantConfig> inside DbConfig, so inference flips
        // TenantConfig's IsReferencedAsNested to true and the aggregate
        // wraps its AddTenantConfig call in .Exists(). With only the "Db"
        // section present, the "__tenant__" section is absent and the
        // TenantConfig validator is never registered — no spurious
        // "[__tenant__:Url] is required" at startup.
        const string Source = """
            using System.Collections.Generic;
            using ConfigBoundNET;

            namespace MyApp;

            [ConfigSection("__tenant__")]
            public partial record TenantConfig
            {
                public string Url { get; init; } = default!;
            }

            [ConfigSection("Db")]
            public partial record DbConfig
            {
                public string Conn { get; init; } = default!;
                public List<TenantConfig> Tenants { get; init; } = new();
            }
            """;

        // Run the aggregate, inspect the service collection afterwards.
        var (assembly, services) = GeneratorHarness.CompileAndAggregate(
            Source,
            new System.Collections.Generic.Dictionary<string, string?>
            {
                ["Db:Conn"] = "Server=localhost",
            });

        var dbConfigType = assembly.GetTypes().Single(t => t.Name == "DbConfig");
        var tenantConfigType = assembly.GetTypes().Single(t => t.Name == "TenantConfig");

        var dbValidatorServiceType = typeof(Microsoft.Extensions.Options.IValidateOptions<>)
            .MakeGenericType(dbConfigType);
        var tenantValidatorServiceType = typeof(Microsoft.Extensions.Options.IValidateOptions<>)
            .MakeGenericType(tenantConfigType);

        // DbConfig's section exists → its validator is registered.
        Assert.Contains(services, sd => sd.ServiceType == dbValidatorServiceType);

        // TenantConfig is inferred-nested and its section is absent →
        // the aggregate's .Exists() gate skipped it, so its validator
        // was never registered at the root.
        Assert.DoesNotContain(services, sd => sd.ServiceType == tenantValidatorServiceType);
    }

    /// <summary>
    /// Reflection helper that mirrors what a real consumer would write
    /// statically as <c>options.Conn</c>. Used here only because the test type
    /// is built dynamically inside the generator harness.
    /// </summary>
    private static object? GetProp(object instance, string name)
        => instance.GetType().GetProperty(name)!.GetValue(instance);
}
